// The ensures of this proof fn is the IMPLICATION
//
//     <ANTECEDENT> ==> det_..._equal(r1, r2, post1_netc, post2_netc)
//
// so the antecedent is NOT a free hypothesis — the prior attempt
// asserted `post1_netc.my_end_point() == pre_netc.my_end_point()` etc.
// at the top level and Verus correctly rejected those (they only hold
// under the implication's antecedent).
//
// Branching on the antecedent expression pulls each conjunct into
// scope inside the `then` arm; that lets us restate the per-run facts
// in tuple-projection form so the trigger sets for `r1` and `r2`
// (originally hidden behind two disjoint `let (ok, Ghost(net_events),
// Ghost(ios)) = ri` bindings) match, then close the success-case
// equalities through the shared `map_sent_packet_seq_to_ios(packets@)`
// pivot using sequence extensionality (`=~=`).
if ({
    &&& (post1_netc.my_end_point() == pre_netc.my_end_point())
    &&& (({
        let (ok, Ghost(net_events), Ghost(ios)) = r1;
        {
            &&& post1_netc.ok() <==> ok
            &&& ok ==> {
                &&& all_ios_are_sends(ios)
                &&& (forall |i: int| 0 <= i && i < net_events.len() ==> net_events[i] is Send)
                &&& ios == map_sent_packet_seq_to_ios(packets@)
                &&& abstractify_outbound_packets_to_seq_of_lsht_packets(packets@) ==
                        extract_sent_packets_from_ios(ios)
                &&& abstractify_seq_of_cpackets_to_set_of_sht_packets(packets@) ==
                        extract_packets_from_abstract_ios(ios)
                &&& no_invalid_sends(ios)
                &&& raw_io_consistent_with_spec_io(net_events, ios)
                &&& only_sent_marshalable_data(net_events)
                &&& post1_netc.history() == pre_netc.history() + net_events
            }
        }
    }))
    &&& (post2_netc.my_end_point() == pre_netc.my_end_point())
    &&& (({
        let (ok, Ghost(net_events), Ghost(ios)) = r2;
        {
            &&& post2_netc.ok() <==> ok
            &&& ok ==> {
                &&& all_ios_are_sends(ios)
                &&& (forall |i: int| 0 <= i && i < net_events.len() ==> net_events[i] is Send)
                &&& ios == map_sent_packet_seq_to_ios(packets@)
                &&& abstractify_outbound_packets_to_seq_of_lsht_packets(packets@) ==
                        extract_sent_packets_from_ios(ios)
                &&& abstractify_seq_of_cpackets_to_set_of_sht_packets(packets@) ==
                        extract_packets_from_abstract_ios(ios)
                &&& no_invalid_sends(ios)
                &&& raw_io_consistent_with_spec_io(net_events, ios)
                &&& only_sent_marshalable_data(net_events)
                &&& post2_netc.history() == pre_netc.history() + net_events
            }
        }
    }))
}) {
    // Inside this arm the antecedent is a hypothesis, so the per-run
    // facts (which the spec hides behind `let (ok, Ghost(_), Ghost(_))
    // = ri` bindings) are now derivable; we restate them in tuple
    // projection form so the SMT triggers match those in
    // `det_..._equal` (which references `(ri.k)@`).

    // End-point preservation, both sides — transitively equal.
    assert(post1_netc.my_end_point() == pre_netc.my_end_point());
    assert(post2_netc.my_end_point() == pre_netc.my_end_point());
    assert(post1_netc.my_end_point() == post2_netc.my_end_point());

    // ok-equivalence: bridge the shadowed local `ok` to `ri.0`.
    assert(post1_netc.ok() <==> r1.0);
    assert(post2_netc.ok() <==> r2.0);

    // r1 success-side conjuncts (unconditional on r1.0).
    if r1.0 {
        assert(all_ios_are_sends((r1.2)@));
        assert((r1.2)@ == map_sent_packet_seq_to_ios(packets@));
        assert(raw_io_consistent_with_spec_io((r1.1)@, (r1.2)@));
        assert(abstractify_raw_log_to_ios((r1.1)@) == (r1.2)@);
        assert(post1_netc.history() == pre_netc.history() + (r1.1)@);
    }

    // r2 success-side conjuncts.
    if r2.0 {
        assert(all_ios_are_sends((r2.2)@));
        assert((r2.2)@ == map_sent_packet_seq_to_ios(packets@));
        assert(raw_io_consistent_with_spec_io((r2.1)@, (r2.2)@));
        assert(abstractify_raw_log_to_ios((r2.1)@) == (r2.2)@);
        assert(post2_netc.history() == pre_netc.history() + (r2.1)@);
    }

    // Joint success: both runs' ios pin to the same functional
    // expression of `packets@`, so they agree extensionally.
    if r1.0 && r2.0 {
        assert((r1.2)@ == map_sent_packet_seq_to_ios(packets@));
        assert((r2.2)@ == map_sent_packet_seq_to_ios(packets@));
        assert((r1.2)@ =~= (r2.2)@);
        assert(abstractify_raw_log_to_ios((r1.1)@) =~= (r1.2)@);
        assert(abstractify_raw_log_to_ios((r2.1)@) =~= (r2.2)@);
        assert(abstractify_raw_log_to_ios((r1.1)@) =~= abstractify_raw_log_to_ios((r2.1)@));
        assert(post1_netc.history() == pre_netc.history() + (r1.1)@);
        assert(post2_netc.history() == pre_netc.history() + (r2.1)@);
    }
}
